import java.util.Scanner;
import java.util.Arrays;

public class SecureBufferExample {
    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);
        System.out.print("Enter a string: ");
        String input = scanner.nextLine();

        // Validate input length to prevent buffer overflow
        if (input.length() > 10) {
            System.out.println("Input exceeds buffer size. Please enter a shorter string.");
            return;
        }

        // Allocate a buffer of appropriate size
        byte[] buffer = new byte[10];

        // Copy input to buffer using safe method
        Arrays.fill(buffer, (byte) 0); // Clear the buffer first
        System.arraycopy(input.getBytes(), 0, buffer, 0, input.length());

        System.out.println("Input successfully copied to buffer: " + new String(buffer));
    }
}

